var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"전방에 침식체 군집 출현! 충돌까지 30초!","JPN":"前方に侵食体の群れが出現！　遭遇まで30秒！","ENG":"C.O. horde up ahead! Contact in 30 seconds!","TWN":"前方有侵蝕體群出現！距離交會還剩30秒！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"너무 가까워, 마리아 아줌마! 뿌리치긴 힘들겠어!","JPN":"近すぎる、マリアおばさん！　撒くのは厳しいよ！","ENG":"They're too close, Maria! We can't shake them off!","TWN":"太近了，瑪麗亞大嬸！很難甩開啊！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"함포 전방으로! 요격되지 않은 개체들은 그대로 돌파한다!","JPN":"艦砲を前方に向けろ！　迎撃できなかった個体はそのまま突破する！","ENG":"Cannons to the front! We push through any remaining C.O.s!","TWN":"用艦炮開路！無法攔截的個體直接突破！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"하아…… 하아…….","JPN":"はぁ……はぁ……","ENG":"*Huff...* *Huff...*","TWN":"哈啊……哈啊……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"이마에 식은땀 좀 봐…….","JPN":"顔に汗がすごいよ……","ENG":"You're sweating...","TWN":"你在流冷汗了……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"기운내, 넘버 5! 넌 할 수 있어!","JPN":"頑張って、ナンバー5！　あなたならできる！","ENG":"Just a little more, number 5! You can do it!","TWN":"加油，5號！你能行的！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"우리 엄마를 생각해서 힘내 줘! 내가 집에 안 들어가면 걱정돼서 잠도 못 주무신다고!","JPN":"私のお母さんのためにも頑張ってくれ！　私が家に帰ってこないと心配で寝れない人なんだ！","ENG":"Or at least keep going for my mom! She'll be worried sick if I don't come home!","TWN":"至少為了我的媽媽加油吧！我要是不回家，她該擔心得睡不著覺了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"너희들 입이 제일 문제야…….","JPN":"もっとマシなセリフを言ってほしいものだ……","ENG":"You two, hold your tongues...","TWN":"你們的嘴才是最大的問題……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"비, 비상! 비상!","JPN":"ひ、非常状態！　非常状態！","ENG":"D-Danger! Danger!","TWN":"緊，緊急情況！緊急情況！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"격납고로 침식체들이 들어오려고 하고 있어요! 어떻게 좀 해 봐요!","JPN":"格納庫に侵食体が入ってこようとしています！　なんとかしてください！","ENG":"C.O.s are trying to come into the hangar! Do something!","TWN":"侵蝕體正試圖闖入機庫！得想想辦法才行！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야! 호들갑 떨 시간에 한 마리라도 더 해치워!","JPN":"おい！　騒いでいる暇があるなら、一匹でも多く倒せ！","ENG":"Why don't you also try killing some then, huh?!","TWN":"喂！有時間大呼小叫的，還是多幹掉一隻吧！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사령관님, 함선에 침입하는 녀석들이 빠르게 늘어나고 있습니다.","JPN":"司令官、艦船に侵入してくる敵が急速に増えています。","ENG":"Commander, the number of C.O.s trying to break into the hangar is growing rapidly.","TWN":"司令官，闖入艦船的侵蝕體正在快速增加。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L24_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"거주 구역은 이미 격벽이 내려갔어. 얼마나 더 걸리는 거야?","JPN":"居住エリアはすでに隔壁で封鎖したわ。あとどのくらいかかるの？","ENG":"We've already lowered the walls in the residential area. How much longer will this take?","TWN":"居住區已經放下隔離牆了。還需要多長時間？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"우리 쪽 함선도 이제 곧 한계야. 더 이상 출력을 높이면 공중 분해되겠어.","JPN":"こちらの艦船ももうすぐ限界だ。これ以上出力を上げたら空中分解する。","ENG":"Our ship is also reaching its limit. If we increase the output anymore, we'll all get blown to bits.","TWN":"我們的艦船也快到達極限了。如果繼續提高輸出，艦船會在空中解體。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"미리 작별인사를 해 둬야 하나? 그쪽 대령과 한 번 더 싸우지 못한 게 아쉽군.","JPN":"先にお別れを言っておいた方が良さそうか？　そっちの大佐ともう一度対戦できなくて残念だ。","ENG":"It is time to say our goodbyes? I am saddened that I couldn't fight your Colonel again.","TWN":"已經要告別了嗎？很遺憾沒能和你們的上校再打一架。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"사령관님! 좌표 신호입니다! 미약하지만 특정되기 시작했습니다!","JPN":"司令官！　座標の信号です！　微弱ですが、特定され始めました！","ENG":"Commander! The coordinate signal! It's weak, but it has started to pick up!","TWN":"司令官！有座標訊號！雖然很微弱，但已經開始鎖定了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"차원계면의 상태는? 보고하도록.","JPN":"次元界面の状態は？　報告しろ。","ENG":"And the status of the Dimension Surface? Report.","TWN":"次元界面的狀態如何？報告一下。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"노출된 부분을 분석했을 때, 구조 강도는 통상의 6배 가량……","JPN":"露出している部分を分析したところ、構造強度はだいたい通常の6倍……","ENG":"Analyzing the exposed portions, the structural force is 6 times the normal...","TWN":"我們分析了暴露的部分，結構強度為普通水準的6倍左右……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"현재 출력으로는 돌파하지 못하고 분쇄되고 맙니다!","JPN":"現在の出力では突破できずに、粉砕されてしまいます！","ENG":"We will get crushed inside with the current output!","TWN":"以現在的輸出無法突破，艦船可能會毀於一旦！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"초대장도 없이 온 손님을 마지막까지 그냥 안 보내 주는군.","JPN":"招待状もなしに来た客は最後までただでは帰らせてくれないようだ。","ENG":"I guess uninvited guests are not allowed to leave as they please, either.","TWN":"不速之客到最後都不願意離開呢。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"실비아, 쿼드 엔진의 최대 출력은 어떻지?","JPN":"シルビア、クワッドエンジンの最大出力はどうなっている？","ENG":"Sylvia, what is the maximum output the Quad Engines can make?","TWN":"希爾維亞，四驅引擎的最大輸出是多少？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"제어 코드는 완성해 뒀어! 이제 100% 마음껏 쓸 수 있을 거야!","JPN":"制御コードは完成したわ！　これで100％自由に使える！","ENG":"I finished the control codes! We can now use 100% anytime we want!","TWN":"控制碼完成了！現在可以完全隨意使用了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……좋아.","JPN":"……よし。","ENG":"...Good.","TWN":"……很好。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"카일, 쿼드 스러스터를 전개한다. 함내에 알리도록.","JPN":"カイル、クワッドスラスターを展開する。艦内に知らせてくれ。","ENG":"Kyle, the Quad Thrusters to full throttle. Inform the crew.","TWN":"凱爾，展開四驅推進器。通知艦船內。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……네! 알겠습니다!","JPN":"……はい！　わかりました！","ENG":"Yes, ma'am! Will do!","TWN":"……是！遵命！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"쿼드 스러스터를 전개합니다! 함내의 승조원들은 충격에 대비해 주십시오!","JPN":"クワッドスラスターを展開します！　艦内の乗組員は衝撃に備えてください！","ENG":"Quad Thrusters to full throttle! Everyone onboard, brace yourselves!","TWN":"展開四驅推進器！艦船內的人員準備應對衝擊！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이런, 결국 사용하는 건가?","JPN":"おや、結局は使うってことか？","ENG":"Oof, so it's come to this?","TWN":"哈，最終還是要用嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"뭐, 뭔가 엄청난 건가요?","JPN":"な、何かすごいものなんでしょうか？","ENG":"I-is it something scary?","TWN":"有，有什麼了不起的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"얼마나 엄청난지는 나도 처음 보는 거야, 아가씨.","JPN":"どれだけすごいのかは俺もまだ見たことがないんだ、お嬢ちゃん。","ENG":"No idea. It's my first time seeing it too, Missy.","TWN":"究竟有多了不起，我也是第一次見識，小姐。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 조심해서 나쁠 건 없을걸. 블랙홀 엔진을.","JPN":"しかし、気をつけて悪いことはないだろうな。ブラックホールエンジンには。","ENG":"But there's no harm in being careful. It is a Blackhole Engine after all.","TWN":"不過小心總歸沒壞處，黑洞引擎。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"다들 아무거나 꽉 붙잡으라고! 잘못 튕겨 나갔다간 바구니 속 달걀처럼 되어 버릴 테니까!","JPN":"全員何でも掴めるものに掴まっておけ！　飛ばされた場所が悪いと焼き卵みたいになっちまうぞ！","ENG":"Grab hold of something! Don't want to see you go flying around like some rodeo!","TWN":"不管什麼東西，大家都抓好了！不小心被彈出去的話，就會變成籃子裡的雞蛋啦！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"차원 도약 준비! 가르강튀아로 보조하겠다!","JPN":"次元跳躍を準備！　ガルガンティアで補助する！","ENG":"Prepare for dimension jump! I will support with Garguantia!","TWN":"準備次元跳躍！我會用加爾剛迪亞輔助！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"다크 세븐 멍청이들! 애 귀찮게 하지 말고 할일에나 집중해!","JPN":"ダークセブンのおバカたち！　この子の邪魔をしないで自分たちのやることに集中して！","ENG":"Hey, Dark Seven goons! Stop annoying her and do your job!","TWN":"嘿！D7的白癡！別去煩她，專心做自己的事！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"……어쩌지? 나 코드 한 줄 잘못 짠 것 같은데?","JPN":"……まずい。コードを一行書き間違えたかも。","ENG":"...Oh no... I think there's a mistake in my code.","TWN":"……怎麼辦？我剛好像寫錯一行程式碼？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"디버깅도 안 했잖아! 정말 바로 실전에 투입하려는 거야?","JPN":"デバッグもやってないじゃない！　本当にいきなり実戦に使うの？","ENG":"It's not even been debugged! Do they really want to just use it?","TWN":"我們都沒做除錯啊！是真的要直接導入實戰嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이제 와서 그딴 말 해도 늦었어! 문제 없이 기동되기만 기도해!","JPN":"今更そんなことを言ったって無駄よ！　ちゃんと動くことだけを祈っといて！","ENG":"It's too late to do anything! Just pray that it works without a hitch!","TWN":"事到如今說這些也晚了！還是祈禱順利啟動吧！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"쿼드 스러스터, 전개!","JPN":"クワッドスラスター、展開！","ENG":"Quad Thrusters, full throttle!","TWN":"四驅推進器，展開！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"카일! 돌파 가능 수준까지는 아직인가?","JPN":"カイル！　突破可能水準になるのはまだか？","ENG":"Kyle! How much more until we can breakthrough?","TWN":"凱爾！還沒到可以突破的水準嗎？"},"stage":{"bg":"MS_1109","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"잔여 1%......!","JPN":"残り1％……！","ENG":"1% remaining...!","TWN":"剩餘1%……！"},"stage":{"bg":"MS_1109","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"도약 가능한 상태까지 1% 남았습니다!","JPN":"跳躍可能になるまであと1％です！","ENG":"There is 1% left until we can jump!","TWN":"距離達到可跳躍的狀態還剩1%！"},"stage":{"bg":"MS_1109","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"쿼드 스러스터는 이미 최대 출력이야! 더 이상은 함선이 못 버텨!","JPN":"クワッドスラスターはすでに最大出力よ！　これ以上は艦船が持たない！","ENG":"The thrusters are already maxed out! The ship can't handle any more!","TWN":"四驅推進器已經是最大輸出了！再高艦船就承受不了了！"},"stage":{"bg":"MS_1109","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"한 발짝만 더…… 한 발짝만 더 내딛을 수 있다면……!","JPN":"もう一歩……あともう一歩踏み出すことができれば……！","ENG":"We are so close... If only we could take a step closer...!","TWN":"一小步……只要能再邁出一小步……！"},"stage":{"bg":"MS_1109","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"어쩌죠! 컨테이너가 막 날아다니는데요!","JPN":"どうしましょうなのです！　コンテナがあちこちから飛んでくるのです！","ENG":"What do we do?! Containers are flying all about!","TWN":"怎麼辦！補給正到處亂飛！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음! 내 다리 옆에 숨어 있게!","JPN":"うむ！　私の脚のそばに隠れておけ！","ENG":"Here! Use my legs as cover!","TWN":"嗯！躲在我腳邊！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L38_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"너무 오래 걸려. 차원 도약에 문제가 생겼나 본데.","JPN":"時間がかかりすぎている。次元跳躍に問題が起きたみたいわね。","ENG":"This is taking too long. Looks like something went wrong with the dimension jump.","TWN":"花太長時間了。次元跳躍似乎出了什麼問題。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"어, 어떡하지? 언제까지 출력을 유지할 수는 없을 텐데……","JPN":"ど、どうしよう？　このままずっと出力を維持することはできないのに……","ENG":"W-what? But the thrusters can't hold their output like this for much longer...","TWN":"怎，怎麼辦？輸出會跟不上的吧……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"조금이라도 가볍게 하면 되지 않아? 격납고를 비워 버리자!","JPN":"少しでも軽くすればいいんじゃねえか？　格納庫を空にしちまおうぜ！","ENG":"What if we lighten the load of the ship? Let's throw away everything in the hangar!","TWN":"稍微減輕一下重量也不行嗎？清空機庫吧！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"함선의 중량이 얼마나 되는지 몰라서 그래? 격납고에 있는 물자만으로는 한참 부족해!","JPN":"艦船がどれだけ重いか知らないの？　格納庫にある物資だけでは全然足りないわ！","ENG":"Do you even know how much this ship weighs? It won't be enough just throwing away hangar inventory!","TWN":"你是不知道艦船的重量有多重嗎？光是丟掉機庫中的物品還遠遠不夠！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그럼 구경만 하자는 거야? 뭐라도 해 봐야지!","JPN":"じゃあ指をくわえて見てろってのか？　何でもやってみなきゃ！","ENG":"Then you just want to wait and twiddle our thumbs? We have to at least try!","TWN":"那就這樣看著嗎？總得做點什麼吧！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"좋아. 나도 거들게.","JPN":"わかった。私も手伝う。","ENG":"Okay. I'll help.","TWN":"好，我也來幫忙。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐? 정말?","JPN":"え？　マジで？","ENG":"Huh? Really?","TWN":"什麼？真的嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"네 말이 맞아. 이 상황에서는 뭐라도 해 봐야지.","JPN":"あんたの言う通りよ。こんな状況では何でもやってみるしかない。","ENG":"You're right. We have to try everything we can.","TWN":"你說的沒錯。這種情況下總得做點什麼。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"기껏 힘들게 옮겼더니 다시 버린다고요!?","JPN":"せっかく頑張って運んだのに、捨てちゃうんですか！？","ENG":"We just moved them here, and now you're going to throw them away?!","TWN":"好不容易搬上來的，又要扔掉？！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"이래서…… 인벤토리에 무게가 있는 시스템은 상황을 탄다니까요…… 흑흑……","JPN":"これだから……インベントリに重さ制限があるシステムは色んな場面で不便なんです……ううっ……","ENG":"This is why... inventory weight systems are the worst... *Sniffle*","TWN":"所以說……背包有空間限制是很討厭的遊戲設定啊……嗚嗚嗚……"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"카일! 용병 친구들이 보급품을 버리기 시작했는데, 가능성이 있겠나?","JPN":"カイル！　傭兵の皆さんが補給品を捨て出したけど、可能性はありそうなのか？","ENG":"Kyle! Our mercenary friends have started to unload the hangar. What is your new assessment?","TWN":"凱爾！傭兵朋友們開始丟棄補給品了，有可能嗎？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"계산 결과로는……","JPN":"計算の結果によると……","ENG":"From my calculations...","TWN":"從計算結果來看……"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"함선에 적재된 장비들을 모두 하역해도, 부족합니다……!","JPN":"艦船に積まれている装備をすべて捨てても、足りません……！","ENG":"It's not enough even if we dispose of all equipment within the ship...!","TWN":"把艦船上裝的裝備全都卸下去也不夠……！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제길……! 조금이면, 정말로 조금이면 되는데……!","JPN":"クソ……！　もう少し、もう少しだというのに……！","ENG":"Dammit...! We just need a little bit more...!","TWN":"該死……！還差一點點，真的就差一點點了……！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"네가 리플레이서 퀸인가?","JPN":"お前がリプレイサー・クイーンか？","ENG":"So you are Replacer Queen?","TWN":"你是克隆·女皇嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L21_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"누, 누구시죠? 이럴 때 갑자기?","JPN":"だ、誰なんですか？　こんな時に？","ENG":"W-who's this? Why are you suddenly calling me?","TWN":"你，你是誰？這時候突然聯繫我有什麼事？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"네가 가진 무기로 추진력을 보탤 생각이라면 중단하라.","JPN":"お前が持っている武器で推進力を足すつもりなら、やめておけ。","ENG":"If you are thinking about using your weapon to add momentum, I suggest you stop.","TWN":"如果你想用你的武器來補充推進力，那我勸你最好不要那麼做。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……보고 계신 건가요? 저를? 어디서?","JPN":"……見ているんですか？　私を？　どこから？","ENG":"...Were you watching me? From where?","TWN":"……你在看著我嗎？你在哪？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"너희 함선의 내부 CCTV를 공유하고 있다. 처음 통신 채널을 개방했을 때.","JPN":"お前たちの艦船の内部監視カメラを共有してもらっている。最初に通信チャンネルを解放してからだ。","ENG":"I gained access to your ship's security cameras. From when the comms channel was open.","TWN":"我在共用你們艦船內部的監控錄影。從最初開放通訊頻道的時候。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"회장이 남긴 괴물도 방해하지 않더군.","JPN":"会長が残した怪物も、邪魔してこなかったな。","ENG":"The President's monster didn't stop me either.","TWN":"會長留下的那個怪物也沒有阻止我。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그렇다면…….","JPN":"それなら……","ENG":"Then...","TWN":"這樣的話……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그렇다면 지금까지 그랬던 것처럼 계속 지켜 보고 계세요.","JPN":"それなら今まで通り、大人しく見ていてください。","ENG":"Then, why don't you just keep observing like you've been doing?","TWN":"這樣的話，你繼續像之前那樣看著就好了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저는 어떻게 해서라도 길을 열고 말겠어요.","JPN":"私はなんとしてでも、道を開いてみせます。","ENG":"I'm going to do anything I can to find a way out.","TWN":"無論如何我都要開出一條路。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그게…… 지금의 저를 증명하는 방법이 될 테니까요.","JPN":"それが……今の自分を証明する方法ですから。","ENG":"Because... that's my way of proving who I am right now.","TWN":"因為……那是證明現在的我的辦法。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"소용없다.","JPN":"無駄だ。","ENG":"It is no use.","TWN":"沒用的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"연산 결과, 너의 초재생 능력으로 감당할 수 없는 출력을 낸다고 한들 대세에는 영향을 끼치지 못한다.","JPN":"演算の結果、お前の超再生能力で耐え切れない程の出力を出したところで、大勢に大きな影響は及ぼせない。","ENG":"According to my calculations, your actions will not affect anything even if you output enough power that exceeds your super regenerative power.","TWN":"運算結果顯示，就算利用你的超再生能力，輸出超過你承受範圍的輸出，也影響不了大局。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"해 보지 않으면 모르는 거잖아요……!","JPN":"やってみないとわかりません……！","ENG":"You don't know unless I try...!","TWN":"沒試過又怎麼知道……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"다들, 다들 여기까지 어떻게 왔는데……! 겨우 희망이 보였는데……!","JPN":"みんな、みんなここまで頑張ってきたのに……！　やっと希望が見え始めていたのに……！","ENG":"You... You don't know what it took to get here...! We finally saw a glimmer of hope...!","TWN":"大家，大家是怎麼走到這裡的……！好不容易看到了希望……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"인간의 힘이란 건 결국 그 정도다.","JPN":"人間の力というのは、所詮その程度だ。","ENG":"That is the limitation of humans.","TWN":"人類的力量最終也就是這個水準。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"인간이라는 개체는 미약하다. 세계가 강요하는 운명에 반드시 패배하게 되어 있지.","JPN":"人間という個体は脆弱だ。世界が強要する運命には必ず屈する運命にある。","ENG":"Humans are frail. They always succumb to the fate imposed by the world.","TWN":"人類這種個體很弱小，必然會敗給世界定下的命運。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그렇다고 해서, 포기할 수는…….","JPN":"だからって、諦めるわけには……","ENG":"Even if so, I can't give u–","TWN":"那也不能就這樣放棄……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 동시에 하나하나가 가능성을 내포한 작은 세계.","JPN":"しかし、それと同時に一人一人が可能性を秘めている小さな世界。","ENG":"But simultaneously, it is a small world with infinite possibilities.","TWN":"但與此同時，每一個小世界裡都蘊含著可能性。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"너희가 가진 숙명이 모인다면, 세계의 운명도 한 번 정도는 바꿀 수 있겠지.","JPN":"お前たち一人一人の宿命が集まれば、世界の運命も一度ぐらいなら変えられるだろう。","ENG":"Perhaps a collection of humans' destinies has the power to alter the fate of the world once.","TWN":"你們的宿命同時聚集到一起的話，至少也能改變一次世界的命運吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"갑자기…… 무슨 소리를…….","JPN":"いきなり……何を……","ENG":"What... are you talking about...?","TWN":"你怎麼……突然說這種話……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"램프 도어를 개방한다! 다들 물러서!","JPN":"ランプドアを解放する！　全員下がれ！","ENG":"Opening the ramp door! Everyone, get back!","TWN":"打開艙門！大家退後！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L2_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"어……? 이건……?","JPN":"え……？　これは……？","ENG":"Huh...? Isn't this...?","TWN":"咦……？這是……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"바람……?","JPN":"風……？","ENG":"Wind...?","TWN":"風……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"후우, 가뜩이나 땀 뻘뻘 흘렸는데 시원하네.","JPN":"ふう、汗っダクダクだったのに、涼しくなったな。","ENG":"Phew. What a nice breeze to cool off your sweat, eh?","TWN":"呼，剛才滿頭大汗的，好涼快啊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"바보야, 정신 차려!","JPN":"ばか、よく考えろ！","ENG":"You idiot! What's wrong with you?!","TWN":"笨蛋，你在想什麼！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"여긴 허수 공간 한복판이라고! 아무것도 없는데 밖에서 바람이 어떻게 불어 와!","JPN":"ここは虚数空間のど真ん中なんだぞ！　何もないのに外から風が吹いてくるなんておかしいだろ！","ENG":"We're in the middle of the imaginary space! How can there be wind if nothing exists?!","TWN":"這裡是虛數空間的正中心！什麼都沒有，外面怎麼會颳風！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"이 바람은, 설마…….","JPN":"この風は、もしや……","ENG":"This wind... Can it be...?","TWN":"這陣風，難道是……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"나는 실패했지만 너희들은 다르길 기대한다.","JPN":"私は失敗したが、お前たちは違うことを期待している。","ENG":"I have failed, but I hope the outcome is different for you.","TWN":"雖然我失敗了，但我期待你們會有不一樣的結果。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그 기대를 확인하기 위해 이곳에 온 것이니까.","JPN":"その期待を確かめるために、私はここに来たのだからな。","ENG":"I am here to witness this expectation.","TWN":"我就是為了確認那份期待才來到了這裡。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};